SELECT o.id, o.code, o.detail, o.address, o.phone, o.remark, o.user_id AS userId, o.product_id AS productId, o.price, o.trade_status AS tradeStatus, o.status, o.create_time AS createTime, o.pay_time AS payTime, p.name AS productName, p.cover_list AS coverList, u.user_name AS sellerName, b.user_name AS buyerName FROM orders o LEFT JOIN product p ON o.product_id = p.id LEFT JOIN user u ON p.user_id = u.id LEFT JOIN user b ON o.user_id = b.id
AND (o.user_id = #{buyerId} OR p.user_id = #{sellerId})
AND o.user_id = #{buyerId}
AND p.user_id = #{sellerId}
AND o.trade_status = #{tradeStatus}
AND o.create_time BETWEEN #{startTime} AND #{endTime}
ORDER BY o.create_time DESC
LIMIT #{current},#{size}

SELECT COUNT(*)
FROM orders o
LEFT JOIN product p ON o.product_id = p.id


